#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline int read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(int x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
CI MAXN=5e3+5;
int n,a[MAXN]={0},f[MAXN][MAXN]={0},ans;
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
    n=read();
    for(int i=1;i<=n;++i)a[i]=read();
    printf("0 ");
    for(int k=2;k<=n;++k)
    {
        ans=inf;
        for(int l=1;l<=n-k+1;++l)
        {
            int r=l+k-1,mid=(l+r)/2;
            f[mid][k]=abs(a[l]-a[r])+f[mid][k-2];
            ans=min(ans,f[mid][k]);
        }
        write(ans);
        putchar(' ');
    }
	return false;
}
